PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE environments ("env_hash" TEXT PRIMARY KEY, "nb_assigned_cores" INTEGER, "nb_available_core" INTEGER, "assigned_memory" INTEGER, "machine_memory" INTEGER, "OS" INTEGER, "kernel_version" TEXT, "activated_modules" TEXT, "cpu_freq" REAL, "cpu_boost" BOOLEAN, "cpu_brand" TEXT, "cpu_model" TEXT, "L1" INTEGER, "L2" INTEGER, "L3" INTEGER);
CREATE TABLE instances ("inst_hash" TEXT PRIMARY KEY, "base_features_runtime" INTEGER, "clauses" INTEGER, "variables" INTEGER, "cls1" INTEGER, "cls2" INTEGER, "cls3" INTEGER, "cls4" INTEGER, "cls5" INTEGER, "cls6" INTEGER, "cls7" INTEGER, "cls8" INTEGER, "cls9" INTEGER, "cls10p" INTEGER, "horn" INTEGER, "invhorn" INTEGER, "positive" INTEGER, "negative" INTEGER, "hornvars_mean" INTEGER, "hornvars_variance" INTEGER, "hornvars_min" INTEGER, "hornvars_max" INTEGER, "hornvars_entropy" INTEGER, "invhornvars_mean" INTEGER, "invhornvars_variance" INTEGER, "invhornvars_min" INTEGER, "invhornvars_max" INTEGER, "invhornvars_entropy" INTEGER, "balancecls_mean" INTEGER, "balancecls_variance" INTEGER, "balancecls_min" INTEGER, "balancecls_max" INTEGER, "balancecls_entropy" INTEGER, "balancevars_mean" INTEGER, "balancevars_variance" INTEGER, "balancevars_min" INTEGER, "balancevars_max" INTEGER, "balancevars_entropy" INTEGER, "vcg_vdegree_mean" INTEGER, "vcg_vdegree_variance" INTEGER, "vcg_vdegree_min" INTEGER, "vcg_vdegree_max" INTEGER, "vcg_vdegree_entropy" INTEGER, "vcg_cdegree_mean" INTEGER, "vcg_cdegree_variance" INTEGER, "vcg_cdegree_min" INTEGER, "vcg_cdegree_max" INTEGER, "vcg_cdegree_entropy" INTEGER, "vg_degree_mean" INTEGER, "vg_degree_variance" INTEGER, "vg_degree_min" INTEGER, "vg_degree_max" INTEGER, "vg_degree_entropy" INTEGER, "cg_degree_mean" INTEGER, "cg_degree_variance" INTEGER, "cg_degree_min" INTEGER, "cg_degree_max" INTEGER, "cg_degree_entropy" INTEGER, "bytes" INTEGER, "ccs" TEXT);
CREATE TABLE solvers ("solver_hash" TEXT PRIMARY KEY, "solver_name" TEXT, "solver_base" TEXT, "competition" TEXT);
CREATE TABLE performances (
    "status" TEXT,
    "perf" INTEGER,
    "inst_hash" TEXT,
    "env_hash" TEXT,
    "solver_hash" TEXT,
    PRIMARY KEY ("inst_hash", "env_hash", "solver_hash"),
    FOREIGN KEY ("inst_hash") REFERENCES instances("hash"),
    FOREIGN KEY ("env_hash") REFERENCES environments("hash"),
    FOREIGN KEY ("solver_hash") REFERENCES solvers("hash")
);
COMMIT;
